1	import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
2	import { Client } from '@opensearch-project/opensearch';
3	
4	import { EnvConfigService } from '@modules/env-config/env-config.service';
5	
6	import {
7		OPENSEARCH_HOST,
8		OPENSEARCH_PASSWORD,
9		OPENSEARCH_USERNAME,
10	} from '@constants/env-variables.constant';
11	
12	import { LogExecution } from '@decorators/log-execution.decorator';
13	
14	@Injectable()
15	export class OpensearchService implements OnModuleInit {
16		private readonly logger = new Logger(OpensearchService.name);
17		private client: Client;
18		private host: string;
19		private username: string;
20		private password: string;
21	
22		constructor(private readonly configService: EnvConfigService) {}
23	
24		onModuleInit(): void {
25			this.initializeOpensearchClient();
26		}
27	
28		private initializeOpensearchClient(): void {
29			try {
30				this.host = this.configService.get<string>({ key: OPENSEARCH_HOST });
31				this.username = this.configService.get<string>({ key: OPENSEARCH_USERNAME });
32				this.password = this.configService.get<string>({ key: OPENSEARCH_PASSWORD });
33	
34				this.client = new Client({
35					node: this.host,
36					auth: {
37						username: this.username,
38						password: this.password,
39					},
40				});
41	
42				this.logger.log(`OpenSearch client initialized successfully. Host: ${this.host}`);
43			} catch (error: unknown) {
44				this.handleError({ context: 'Failed to initialize OpenSearch client', error });
45				throw error;
46			}
47		}
48	
49		@LogExecution()
50		async healthCheck(): Promise<{ status: string; cluster_name: string }> {
51			try {
52				const response = await this.client.cluster.health();
53				return {
54					status: response.body.status,
55					cluster_name: response.body.cluster_name,
56				};
57			} catch (error: unknown) {
58				this.handleError({ context: 'OpenSearch health check failed', error });
59				throw error;
60			}
61		}
62	
63		getClient(): Client {
64			return this.client;
65		}
66	
67		@LogExecution()
68		async createIndex({
69			indexName,
70			mappings,
71			settings,
72		}: {
73			indexName: string;
74			mappings: Record<string, unknown>;
75			settings: Record<string, unknown>;
76		}): Promise<void> {
77			try {
78				const exists = await this.client.indices.exists({ index: indexName });
79	
80				if (exists.body) {
81					this.logger.log(`Index ${indexName} already exists`);
82					return;
83				}
84	
85				await this.client.indices.create({
86					index: indexName,
87					body: {
88						settings,
89						mappings,
90					},
91				});
92	
93				this.logger.log(`Created OpenSearch index: ${indexName}`);
94			} catch (error: unknown) {
95				this.handleError({ context: `Failed to create index ${indexName}`, error });
96				throw error;
97			}
98		}
99	
100		@LogExecution({ logParams: false, logResponse: false })
101		async bulkIndex({
102			indexName,
103			documents,
104		}: {
105			indexName: string;
106			documents: { _id: string; [key: string]: unknown }[];
107		}): Promise<{ indexed: number; errors: number }> {
108			try {
109				if (documents.length === 0) {
110					return { indexed: 0, errors: 0 };
111				}
112	
113				const body = documents.flatMap((doc) => {
114					const { _id, ...docWithoutId } = doc;
115					return [{ index: { _index: indexName, _id } }, docWithoutId];
116				});
117	
118				const response = await this.client.bulk({ body });
119	
120				const errorItems = response.body.items.filter(
121					(item: { index?: { error?: unknown } }) => item.index?.error,
122				);
123	
124				const errors = errorItems.length;
125				const indexed = documents.length - errors;
126	
127				if (errors > 0) {
128					this.logger.warn(
129						`Bulk index completed with ${errors} errors out of ${documents.length} documents`,
130					);
131	
132					const sampleErrors = errorItems
133						.slice(0, 3)
134						.map((item: { index?: { error?: { type?: string; reason?: string } } }) => ({
135							type: item.index?.error?.type,
136							reason: item.index?.error?.reason,
137						}));
138	
139					this.logger.error(`Sample errors: ${JSON.stringify(sampleErrors, null, 2)}`);
140				}
141	
142				return { indexed, errors };
143			} catch (error: unknown) {
144				this.handleError({ context: 'Bulk index failed', error });
145				throw error;
146			}
147		}
148	
149		@LogExecution()
150		async configureClusterMLSettings(): Promise<void> {
151			try {
152				await this.client.cluster.putSettings({
153					body: {
154						persistent: {
155							'plugins.ml_commons.only_run_on_ml_node': false,
156							'plugins.ml_commons.model_access_control_enabled': true,
157							'plugins.ml_commons.native_memory_threshold': 99,
158						},
159					},
160				});
161				this.logger.log('Configured ML cluster settings');
162			} catch (error: unknown) {
163				this.handleError({ context: 'Failed to configure ML cluster settings', error });
164				throw error;
165			}
166		}
167	
168		@LogExecution()
169		async registerModelGroup({
170			name,
171			description,
172		}: {
173			name: string;
174			description: string;
175		}): Promise<string> {
176			try {
177				const response = await this.client.transport.request({
178					method: 'POST',
179					path: '/_plugins/_ml/model_groups/_register',
180					body: { name, description },
181				});
182	
183				const modelGroupId = (response.body as { model_group_id: string }).model_group_id;
184				this.logger.log(`Registered model group: ${modelGroupId}`);
185				return modelGroupId;
186			} catch (error: unknown) {
187				this.handleError({ context: 'Failed to register model group', error });
188				throw error;
189			}
190		}
191	
192		@LogExecution()
193		async registerModel({
194			name,
195			version,
196			modelGroupId,
197			modelFormat,
198		}: {
199			name: string;
200			version: string;
201			modelGroupId: string;
202			modelFormat: string;
203		}): Promise<string> {
204			try {
205				const response = await this.client.transport.request({
206					method: 'POST',
207					path: '/_plugins/_ml/models/_register',
208					body: {
209						name,
210						version,
211						model_group_id: modelGroupId,
212						model_format: modelFormat,
213					},
214				});
215	
216				const taskId = (response.body as { task_id: string }).task_id;
217				this.logger.log(`Model registration started, taskId: ${taskId}`);
218				return taskId;
219			} catch (error: unknown) {
220				this.handleError({ context: 'Failed to register model', error });
221				throw error;
222			}
223		}
224	
225		@LogExecution()
226		async deployModel({ modelId }: { modelId: string }): Promise<string> {
227			try {
228				const response = await this.client.transport.request({
229					method: 'POST',
230					path: `/_plugins/_ml/models/${modelId}/_deploy`,
231				});
232	
233				const taskId = (response.body as { task_id: string }).task_id;
234				this.logger.log(`Model deployment started, taskId: ${taskId}`);
235				return taskId;
236			} catch (error: unknown) {
237				this.handleError({ context: `Failed to deploy model ${modelId}`, error });
238				throw error;
239			}
240		}
241	
242		@LogExecution()
243		async getTask({ taskId }: { taskId: string }): Promise<{
244			state: string;
245			model_id?: string;
246		}> {
247			try {
248				const response = await this.client.transport.request({
249					method: 'GET',
250					path: `/_plugins/_ml/tasks/${taskId}`,
251				});
252	
253				const body = response.body as { state: string; model_id?: string };
254				return {
255					state: body.state,
256					...(body.model_id !== undefined && { model_id: body.model_id }),
257				};
258			} catch (error: unknown) {
259				this.handleError({ context: `Failed to get task ${taskId}`, error });
260				throw error;
261			}
262		}
263	
264		@LogExecution()
265		async waitForTask({
266			taskId,
267			intervalMs = 5000,
268			maxAttempts = 60,
269		}: {
270			taskId: string;
271			intervalMs?: number;
272			maxAttempts?: number;
273		}): Promise<{ state: string; model_id?: string }> {
274			for (let attempt = 1; attempt <= maxAttempts; attempt++) {
275				const task = await this.getTask({ taskId });
276				this.logger.log(
277					`Task ${taskId} — attempt ${attempt}/${maxAttempts}, state: ${task.state}`,
278				);
279	
280				if (task.state === 'COMPLETED') {
281					return task;
282				}
283	
284				if (task.state === 'FAILED') {
285					throw new Error(`Task ${taskId} failed`);
286				}
287	
288				await new Promise((resolve) => setTimeout(resolve, intervalMs));
289			}
290	
291			throw new Error(`Task ${taskId} timed out after ${maxAttempts} attempts`);
292		}
293	
294		@LogExecution()
295		async createIngestPipeline({
296			pipelineId,
297			modelId,
298			sourceField,
299			targetField,
300		}: {
301			pipelineId: string;
302			modelId: string;
303			sourceField: string;
304			targetField: string;
305		}): Promise<void> {
306			try {
307				await this.client.ingest.putPipeline({
308					id: pipelineId,
309					body: {
310						description: `Neural search ingest pipeline: ${sourceField} -> ${targetField}`,
311						processors: [
312							{
313								text_embedding: {
314									model_id: modelId,
315									field_map: {
316										[sourceField]: targetField,
317									},
318								},
319							},
320						],
321					},
322				});
323				this.logger.log(`Created ingest pipeline: ${pipelineId}`);
324			} catch (error: unknown) {
325				this.handleError({
326					context: `Failed to create ingest pipeline ${pipelineId}`,
327					error,
328				});
329				throw error;
330			}
331		}
332	
333		@LogExecution()
334		async createSearchPipeline({
335			pipelineId,
