	@LogExecution()
	async deleteSearchPipeline({ pipelineId }: { pipelineId: string }): Promise<void> {
		try {
			await this.client.transport.request({
				method: 'DELETE',
				path: `/_search/pipeline/${pipelineId}`,
			});
