1	import { Logger } from '@nestjs/common';
2	import { Command, CommandRunner, Option } from 'nest-commander';
3	
4	import { StylesMvModel } from '@modules/db/styles-mv/models/styles-mv.model';
5	import { EnvConfigService } from '@modules/env-config/env-config.service';
6	import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
7	import { OpensearchService } from '@modules/opensearch/opensearch.service';
8	
9	import { runWithConcurrencyLimit } from '@utils/concurrency-pool.util';
10	import { ProgressBar } from '@utils/progress-bar.util';
11	
12	import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
13	
14	import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
15	
16	const MODEL_NAME = 'huggingface/sentence-transformers/all-distilroberta-v1';
17	const MODEL_VERSION = '1.0.1';
18	const MODEL_GROUP_NAME = 'neural-search-model-group';
19	const INGEST_PIPELINE_ID = 'products-neural-pipeline';
20	const SEARCH_PIPELINE_ID = 'hybrid-search-pipeline';
21	
22	interface BootstrapNeuralSearchOptions {
23		modelFormat?: string;
24		batchSize?: number;
25		concurrency?: number;
26		cleanup?: boolean;
27	}
28	
29	@Command({
30		name: 'bootstrap-neural-search',
31		description:
32			'Full neural search bootstrap: configure cluster, train model, create index, sync products',
33	})
34	export class BootstrapNeuralSearchCommand extends CommandRunner {
35		private readonly logger = new Logger(BootstrapNeuralSearchCommand.name);
36		private isShuttingDown = false;
37		private currentOperation: Promise<void> | null = null;
38		private isCancelled = false;
39	
40		constructor(
41			private readonly opensearchService: OpensearchService,
42			private readonly opensearchNeuralService: OpensearchNeuralService,
43			private readonly stylesMvModel: StylesMvModel,
44			private readonly configService: EnvConfigService,
45		) {
46			super();
47			this.setupGracefulShutdown();
48		}
49	
50		@CronJobExecution({ jobName: 'bootstrap-neural-search' })
51		async run(
52			_passedParams: string[],
53			options: BootstrapNeuralSearchOptions,
54		): Promise<void> {
55			if (this.isShuttingDown) {
56				this.logger.warn('Command cancelled due to shutdown signal');
57				return;
58			}
59	
60			const modelFormat = options.modelFormat ?? 'TORCH_SCRIPT';
61			const batchSize = options.batchSize ?? 60;
62			const concurrency = options.concurrency ?? 2;
63			const cleanup = options.cleanup ?? false;
64			const totalSteps = cleanup ? 9 : 8;
65			const startTime = Date.now();
66	
67			try {
68				const indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
69	
70				let step = 1;
71	
72				if (cleanup) {
73					this.logger.log(
74						`=== Step ${step++}/${totalSteps}: Cleaning up existing resources ===`,
75					);
76					await this.cleanupExistingResources({ indexName });
77				}
78	
79				this.logger.log(
80					`=== Step ${step++}/${totalSteps}: Configuring cluster ML settings ===`,
81				);
82				await this.opensearchService.configureClusterMLSettings();
83	
84				this.logger.log(`=== Step ${step++}/${totalSteps}: Registering model group ===`);
85				const modelGroupId = await this.opensearchService.registerModelGroup({
86					name: MODEL_GROUP_NAME,
87					description: 'Model group for neural search embeddings',
88				});
89	
90				this.logger.log(
91					`=== Step ${step++}/${totalSteps}: Registering model (this may take several minutes) ===`,
92				);
93				const registerTaskId = await this.opensearchService.registerModel({
94					name: MODEL_NAME,
95					version: MODEL_VERSION,
96					modelGroupId,
97					modelFormat,
98				});
99	
100				this.logger.log('Waiting for model registration to complete...');
101				const registerResult = await this.opensearchService.waitForTask({
102					taskId: registerTaskId,
103					intervalMs: 10000,
104					maxAttempts: 120,
105				});
106				const modelId = registerResult.model_id;
107	
108				if (!modelId) {
109					throw new Error('Model registration completed but no model_id returned');
110				}
111	
112				this.logger.log(`Model registered: ${modelId}`);
113	
114				this.logger.log(
115					`=== Step ${step++}/${totalSteps}: Deploying model (this may take several minutes) ===`,
116				);
117				const deployTaskId = await this.opensearchService.deployModel({ modelId });
118	
119				this.logger.log('Waiting for model deployment to complete...');
120				await this.opensearchService.waitForTask({
121					taskId: deployTaskId,
122					intervalMs: 10000,
123					maxAttempts: 120,
124				});
125				this.logger.log('Model deployed successfully');
126	
127				this.logger.log(`=== Step ${step++}/${totalSteps}: Creating ingest pipeline ===`);
128				await this.opensearchService.createIngestPipeline({
129					pipelineId: INGEST_PIPELINE_ID,
130					modelId,
131					sourceField: 'combined_text_for_embedding',
132					targetField: 'product_embedding',
133				});
134	
135				this.logger.log(`=== Step ${step++}/${totalSteps}: Creating search pipeline ===`);
136				await this.opensearchService.createSearchPipeline({
137					pipelineId: SEARCH_PIPELINE_ID,
138					normalizationTechnique: 'min_max',
139					combinationTechnique: 'arithmetic_mean',
140					weights: [0.1, 0.9],
141				});
142	
143				this.logger.log(
144					`=== Step ${step++}/${totalSteps}: Creating index ${indexName} ===`,
145				);
146				await this.opensearchNeuralService.createProductsIndex({ indexName });
147	
148				if (this.isCancelled) {
149					this.logger.warn('Bootstrap cancelled before product sync');
150					return;
151				}
152	
153				this.logger.log(
154					`=== Step ${step}/${totalSteps}: Syncing products (embedding generation on ingest) ===`,
155				);
156				this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
157	
158				const totalCount = await this.stylesMvModel.count();
159				this.logger.log(`Total products to index: ${totalCount}`);
160	
161				if (totalCount === 0) {
162					this.logger.warn('No products found to index');
163					return;
164				}
165	
166				const totalBatches = Math.ceil(totalCount / batchSize);
167				const batches = Array.from({ length: totalBatches }, (_, i) => ({
168					offset: i * batchSize,
169					limit: batchSize,
170				}));
171	
172				const progressBar = new ProgressBar({ total: totalCount });
173				let totalIndexed = 0;
174				let totalErrors = 0;
175	
176				this.currentOperation = this.processBatches({
177					batches,
178					concurrency,
179					indexName,
180					progressBar,
181					onBatchComplete: (indexed, errors) => {
182						totalIndexed += indexed;
183						totalErrors += errors;
184					},
185				});
186	
187				await this.currentOperation;
188	
189				// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
190				if (!this.isCancelled) {
191					progressBar.finish();
192				}
193	
194				const duration = ((Date.now() - startTime) / 1000).toFixed(1);
195	
196				this.logger.log('=== Bootstrap complete ===');
197				this.logger.log(`Duration: ${duration}s`);
198				this.logger.log(`Products indexed: ${totalIndexed}, Errors: ${totalErrors}`);
199				this.logger.log(`Model ID: ${modelId} (resolved dynamically at app startup)`);
200			} catch (error) {
201				// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
202				if (this.isShuttingDown || this.isCancelled) {
203					this.logger.warn('Command interrupted during shutdown');
204					return;
205				}
206				this.logger.error(`Bootstrap failed: ${(error as Error).message}`);
207				process.exit(1);
208			} finally {
209				this.currentOperation = null;
210			}
211		}
212	
213		private async cleanupExistingResources({
214			indexName,
215		}: {
216			indexName: string;
217		}): Promise<void> {
218			this.logger.log('Deleting index...');
219			await this.opensearchService.deleteIndex({ indexName });
220	
221			this.logger.log('Deleting pipelines...');
222			await this.opensearchService.deleteSearchPipeline({ pipelineId: SEARCH_PIPELINE_ID });
223			await this.opensearchService.deleteIngestPipeline({ pipelineId: INGEST_PIPELINE_ID });
224	
225			this.logger.log('Looking for existing model group...');
226			const modelGroupId = await this.opensearchService.searchModelGroupByName({
227				name: MODEL_GROUP_NAME,
228			});
229	
230			if (modelGroupId) {
231				this.logger.log(`Found model group: ${modelGroupId}, cleaning up models...`);
232				const models = await this.opensearchService.searchModelsByGroup({ modelGroupId });
233	
234				for (const model of models) {
235					if (model.model_state === 'DEPLOYED' || model.model_state === 'DEPLOYING') {
236						this.logger.log(`Undeploying model: ${model.model_id}`);
237						await this.opensearchService.undeployModel({ modelId: model.model_id });
238						await new Promise((resolve) => setTimeout(resolve, 3000));
239					}
